mapper.select:
SELECT * FROM top_inst
WHERE trade_date = #{tradeDate} AND ts_code = #{tsCode}
ORDER BY side, net_buy DESC

SELECT * FROM top_inst WHERE trade_date = #{tradeDate}
AND (

    exalter LIKE CONCAT('%', #{kw}, '%')

)
ORDER BY net_buy DESC

SELECT COUNT(*) FROM top_inst
WHERE trade_date >= #{startDate}
  AND (buy < 0 OR sell < 0)

SELECT COUNT(*) FROM top_inst t
WHERE t.trade_date >= #{startDate}
  AND NOT EXISTS (
      SELECT 1 FROM top_list l
      WHERE l.trade_date = t.trade_date AND l.ts_code = t.ts_code
  )
